      import { getDb } from "./db.js";

const COL = "memory_messages";

export async function addTurn({ mongoUri, platform, userId, chatId, role, text }) {
  const db = await getDb(mongoUri);
  const doc = {
    platform,
    userId: String(userId),
    chatId: chatId ? String(chatId) : "",
    role,
    text: String(text || "").slice(0, 4000),
    ts: new Date(),
  };

  if (!db) return; // allow bot to run without DB
  await db.collection(COL).insertOne(doc);
}

export async function getRecentTurns({ mongoUri, platform, userId, chatId, limit = 14 }) {
  const db = await getDb(mongoUri);
  if (!db) return [];

  const q = {
    platform,
    userId: String(userId),
  };
  if (chatId) q.chatId = String(chatId);

  const rows = await db
    .collection(COL)
    .find(q)
    .sort({ ts: -1 })
    .limit(limit)
    .toArray();

  // return chronological
  return rows.reverse().map((r) => ({ role: r.role, text: r.text }));
}

export async function clearUserMemory({ mongoUri, platform, userId, chatId }) {
  const db = await getDb(mongoUri);
  if (!db) return;

  const q = { platform, userId: String(userId) };
  if (chatId) q.chatId = String(chatId);

  await db.collection(COL).deleteMany(q);
}

rateLimit.js.content:
const lastByUser = new Map();

export function checkCooldown({ userId, cooldownMs }) {
  const uid = String(userId || "");
  if (!uid) return { ok: true, remainingMs: 0 };

  const now = Date.now();
  const last = lastByUser.get(uid) || 0;
  const diff = now - last;
  if (diff >= cooldownMs) {
    lastByUser.set(uid, now);
    return { ok: true, remainingMs: 0 };
  }
  return { ok: false, remainingMs: cooldownMs - diff };
}

const lastHintByUser = new Map();

export function shouldHint({ userId, everyMs }) {
  const uid = String(userId || "");
  if (!uid) return true;

  const now = Date.now();
  const last = lastHintByUser.get(uid) || 0;
  if (now - last >= everyMs) {
    lastHintByUser.set(uid, now);
    return true;
  }
  return false;
}

